import{_ as t,M as a,p as n,q as o,R as e,t as r,N as i,a1 as l}from"./framework-188d6338.js";const d={},c={id:"fuse-cloud",tabindex:"-1"},u=e("a",{class:"header-anchor",href:"#fuse-cloud","aria-hidden":"true"},"#",-1),h=l(`<p><strong>Upload JSON. Get a search API. Same fuzzy search you know.</strong></p><p>Fuse Cloud turns your Fuse.js setup into a hosted search service. No infrastructure, no new mental model — if you know Fuse.js, you already know how this works.</p><hr><h2 id="the-problem" tabindex="-1"><a class="header-anchor" href="#the-problem" aria-hidden="true">#</a> The Problem</h2><p>Fuse.js works great until your dataset outgrows the browser — too many records, too slow on mobile, or multiple users need to search the same data. At that point, the options are Algolia, Elasticsearch, or Meilisearch — all powerful, all complex, all a completely different system to learn.</p><p><strong>Fuse Cloud fills the gap:</strong> scale your search without switching your mental model.</p><hr><h2 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works" aria-hidden="true">#</a> How It Works</h2><ol><li><strong>Upload your data</strong> — Push a JSON array, the same format you already use with Fuse.js.</li><li><strong>Get a search API</strong> — Fuse Cloud indexes your data and gives you a public key.</li><li><strong>Search from the client</strong> — Call the API directly from your frontend. No backend required.</li></ol><hr><h2 id="what-it-looks-like" tabindex="-1"><a class="header-anchor" href="#what-it-looks-like" aria-hidden="true">#</a> What It Looks Like</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> FuseCloud <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&quot;@fusejs/cloud&quot;</span>

<span class="token keyword">const</span> client <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FuseCloud</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">publicKey</span><span class="token operator">:</span> <span class="token string">&quot;pk_abc123&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">index</span><span class="token operator">:</span> <span class="token string">&quot;products&quot;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> <span class="token punctuation">{</span> results <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token keyword">await</span> client<span class="token punctuation">.</span><span class="token function">search</span><span class="token punctuation">(</span><span class="token string">&quot;iphone&quot;</span><span class="token punctuation">)</span>
<span class="token comment">// → [{ id: &quot;1&quot;, score: 0.02, item: { title: &quot;iPhone 16 Pro&quot;, ... } }]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Same results format as Fuse.js. Same scoring. Same fuzzy matching.</p><hr><h2 id="why-fuse-cloud" tabindex="-1"><a class="header-anchor" href="#why-fuse-cloud" aria-hidden="true">#</a> Why Fuse Cloud</h2><table><thead><tr><th></th><th>Fuse.js (local)</th><th>Fuse Cloud</th><th>Algolia / Meilisearch</th></tr></thead><tbody><tr><td>Setup time</td><td>Minutes</td><td>Minutes</td><td>Hours</td></tr><tr><td>Infrastructure</td><td>None</td><td>Managed</td><td>Self-hosted or vendor</td></tr><tr><td>Mental model</td><td>Fuse.js</td><td>Fuse.js</td><td>New system</td></tr><tr><td>Best for</td><td>Small datasets</td><td>Medium–large datasets</td><td>Large-scale search</td></tr><tr><td>Pricing</td><td>Free</td><td>Free tier + paid plans</td><td>Varies</td></tr></tbody></table><hr><h2 id="pricing" tabindex="-1"><a class="header-anchor" href="#pricing" aria-hidden="true">#</a> Pricing</h2><p><strong>Free tier included.</strong> Paid plans for higher usage. Pricing details coming soon.</p><hr><h2 id="who-this-is-for" tabindex="-1"><a class="header-anchor" href="#who-this-is-for" aria-hidden="true">#</a> Who This Is For</h2><ul><li><strong>Documentation sites</strong> — power your search bar without loading the full dataset client-side</li><li><strong>Product catalogs</strong> — fuzzy search across thousands of products from a static site or SPA</li><li><strong>Internal tools</strong> — search across company data without building a search backend</li><li><strong>Content libraries</strong> — articles, recipes, courses — anything you&#39;d search with Fuse.js today</li></ul><h2 id="who-this-is-not-for" tabindex="-1"><a class="header-anchor" href="#who-this-is-not-for" aria-hidden="true">#</a> Who This Is Not For</h2><ul><li><strong>Enterprise search</strong> — if you need faceting, analytics, A/B testing, and dedicated support, look at Algolia or Typesense</li><li><strong>Real-time data</strong> — if your data changes every second, you need a different architecture</li><li><strong>Sensitive/regulated data</strong> — if compliance requirements (HIPAA, SOC2) are a blocker, this isn&#39;t ready for that yet</li></ul><hr><h2 id="interested" tabindex="-1"><a class="header-anchor" href="#interested" aria-hidden="true">#</a> Interested?</h2><p>Fuse Cloud is in early development. Get early access and help shape what gets built.</p><div class="cloud-signup"><a href="https://tally.so/r/Zjz8qo" class="cloud-btn" target="_blank" rel="noopener">Get Early Access</a><p class="cloud-note">Or share your use case in the <a href="https://github.com/krisk/Fuse/discussions/819">GitHub Discussion</a>.</p></div>`,28);function p(g,m){const s=a("Badge");return n(),o("div",null,[e("h1",c,[u,r(" Fuse Cloud "),i(s,{type:"warning",text:"Coming Soon"})]),h])}const y=t(d,[["render",p],["__file","cloud.html.vue"]]);export{y as default};
